const (
	maxWitnessDepth      = 2
	maxArrayItems        = 100
	maxFailedItemBytes   = 8 * 1024
	maxPredicateSourceKB = 4 * 1024
)

var redactionPatterns = []string{"password", "token", "secret", "api_key", "apikey"}

var witnessMu sync.Mutex
var witnessSeq int

// emitWitness writes a witness JSON file to the STELE_WITNESS_DIR.
func emitWitness(t *testing.T, w *FailureWitness) {
	dir := os.Getenv("STELE_WITNESS_DIR")
	if dir == "" {
		return
	}
	safeName := strings.ReplaceAll(t.Name(), "/", "_")
	witnessMu.Lock()
	witnessSeq++
	seq := witnessSeq
	witnessMu.Unlock()
	filename := fmt.Sprintf("%s-%04d.json", safeName, seq)
	path := filepath.Join(dir, filename)
	data, _ := json.Marshal(map[string]any{
		"test_name": t.Name(),
		"witness":   w,
	})
	_ = os.WriteFile(path, data, 0644)
}

