// safeSerialize defensively serializes a failure item, limiting depth,
// array length, and byte size. Mirrors safeSerialize() in @stele/core.
func safeSerialize(value any, maxDepth int) string {
	result, _ := safeSerializeTree(value, maxDepth, 0)
	data, err := json.Marshal(result)
	if err != nil {
		return `{"_truncated":true,"_serialize_error":true}`
	}
	if len(data) > maxFailedItemBytes {
		return fmt.Sprintf(`{"_truncated":true,"_original_size":%d}`, len(data))
	}
	return string(data)
}

func safeSerializeTree(value any, maxDepth, depth int) (any, bool) {
	if depth > maxDepth {
		return "<depth-limit>", true
	}
	if value == nil {
		return nil, false
	}

	switch v := value.(type) {
	case []any:
		if len(v) > maxArrayItems {
			v = v[:maxArrayItems]
		}
		out := make([]any, len(v))
		truncated := false
		for i, item := range v {
			var t bool
			out[i], t = safeSerializeTree(item, maxDepth, depth+1)
			if t {
				truncated = true
			}
		}
		return out, truncated
	case map[string]any:
		out := make(map[string]any)
		truncated := false
		for key, item := range v {
			if shouldRedact(key) {
				out[key] = "<redacted>"
				continue
			}
			var t bool
			out[key], t = safeSerializeTree(item, maxDepth, depth+1)
			if t {
				truncated = true
			}
		}
		return out, truncated
	default:
		return v, false
	}
}

func shouldRedact(key string) bool {
	lower := strings.ToLower(key)
	for _, pat := range redactionPatterns {
		if strings.Contains(lower, pat) {
			return true
		}
	}
	return false
}

