// steleNumeric lifts arbitrary numeric types to (int64, float64, isFloat).
// Returns an error for non-numeric types.
func steleNumeric(v any) (int64, float64, bool, error) {
	switch n := v.(type) {
	case int:
		return int64(n), float64(n), false, nil
	case int8:
		return int64(n), float64(n), false, nil
	case int16:
		return int64(n), float64(n), false, nil
	case int32:
		return int64(n), float64(n), false, nil
	case int64:
		return n, float64(n), false, nil
	case uint:
		return int64(n), float64(n), false, nil
	case uint8:
		return int64(n), float64(n), false, nil
	case uint16:
		return int64(n), float64(n), false, nil
	case uint32:
		return int64(n), float64(n), false, nil
	case uint64:
		if n > math.MaxInt64 {
			return 0, float64(n), true, nil
		}
		return int64(n), float64(n), false, nil
	case float32:
		return int64(n), float64(n), true, nil
	case float64:
		if n == math.Trunc(n) && !math.IsInf(n, 0) {
			return int64(n), n, false, nil
		}
		return 0, n, true, nil
	case json.Number:
		if i, err := n.Int64(); err == nil {
			return i, float64(i), false, nil
		}
		if f, err := n.Float64(); err == nil {
			return 0, f, true, nil
		}
		return 0, 0, false, fmt.Errorf("cannot parse number: %s", n)
	default:
		return 0, 0, false, fmt.Errorf("expected number, got %T", v)
	}
}

// steleTryNumeric attempts to parse an arbitrary value as float64.
// Handles string representations of numbers ("42", "3.14") that steleNumeric
// does not cover. Returns (float64, true) on success, (0, false) on failure.
func steleTryNumeric(v any) (float64, bool) {
	switch n := v.(type) {
	case string:
		if i, err := strconv.ParseInt(n, 10, 64); err == nil {
			return float64(i), true
		}
		if f, err := strconv.ParseFloat(n, 64); err == nil {
			return f, true
		}
		return 0, false
	case json.Number:
		if f, err := n.Float64(); err == nil {
			return f, true
		}
		return 0, false
	default:
		s := fmt.Sprint(v)
		if f, err := strconv.ParseFloat(s, 64); err == nil {
			return f, true
		}
		return 0, false
	}
}

