// steleEq compares two values with numeric tolerance and fallback to reflect.DeepEqual.
func steleEq(a, b any) bool {
	ai, af, aIsFloat, aErr := steleNumeric(a)
	bi, bf, bIsFloat, bErr := steleNumeric(b)
	if aErr != nil || bErr != nil {
		aNum, aOk := steleTryNumeric(a)
		bNum, bOk := steleTryNumeric(b)
		if aOk && bOk {
			return math.Abs(aNum-bNum) < 1e-9
		}
		return reflect.DeepEqual(a, b)
	}
	if aIsFloat || bIsFloat {
		return math.Abs(af-bf) < 1e-9
	}
	return ai == bi
}

func steleNeq(a, b any) bool {
	return !steleEq(a, b)
}

func steleGt(a, b any) bool {
	return steleNumericCompare("gt", a, b) > 0
}

func steleGte(a, b any) bool {
	return steleNumericCompare("gt", a, b) >= 0
}

func steleLt(a, b any) bool {
	return steleNumericCompare("lt", a, b) < 0
}

func steleLte(a, b any) bool {
	return steleNumericCompare("lte", a, b) <= 0
}

func steleNumericCompare(op string, a, b any) int {
	ai, _, aF, aErr := steleNumeric(a)
	bi, _, bF, bErr := steleNumeric(b)
	if aErr != nil || bErr != nil {
		an, aOk := steleTryNumeric(a)
		bn, bOk := steleTryNumeric(b)
		if !aOk || !bOk {
			panic(fmt.Sprintf("cannot compare %T and %T in %s", a, b, op))
		}
		if math.Abs(an-bn) < 1e-9 {
			return 0
		}
		if an < bn {
			return -1
		}
		return 1
	}
	if aF || bF {
		af := toFloat(a, op)
		bf := toFloat(b, op)
		if math.Abs(af-bf) < 1e-9 {
			return 0
		}
		if af < bf {
			return -1
		}
		return 1
	}
	if ai < bi {
		return -1
	}
	if ai > bi {
		return 1
	}
	return 0
}

