func steleAdd(operands ...any) float64 {
	if len(operands) < 2 {
		panic(fmt.Sprintf("add: expected at least 2 operands, got %d", len(operands)))
	}
	var total float64
	for _, op := range operands {
		total += toFloat(op, "add")
	}
	return total
}

func steleSub(a, b any) float64 {
	return toFloat(a, "sub") - toFloat(b, "sub")
}

func steleMul(operands ...any) float64 {
	if len(operands) < 2 {
		panic(fmt.Sprintf("mul: expected at least 2 operands, got %d", len(operands)))
	}
	result := float64(1)
	for _, op := range operands {
		result *= toFloat(op, "mul")
	}
	return result
}

func steleDiv(a, b any) float64 {
	divisor := toFloat(b, "div")
	if divisor == 0 {
		panic("div: division by zero")
	}
	return toFloat(a, "div") / divisor
}

func steleNeg(a any) float64 {
	return -toFloat(a, "neg")
}

func steleAbs(a any) float64 {
	return math.Abs(toFloat(a, "abs"))
}

func steleMod(a, b any) float64 {
	divisor := toFloat(b, "mod")
	if divisor == 0 {
		panic("mod: divisor cannot be zero")
	}
	// sign-of-divisor (Python semantics): ((a%b)+b)%b
	aVal := toFloat(a, "mod")
	return math.Mod(math.Mod(aVal, divisor)+divisor, divisor)
}

func stelePow(a, b any) float64 {
	return math.Pow(toFloat(a, "pow"), toFloat(b, "pow"))
}

func steleRound(a any, digits ...any) float64 {
	val := toFloat(a, "round")
	d := float64(0)
	if len(digits) > 0 {
		d = toFloat(digits[0], "round")
	}
	if !math.IsInf(d, 0) && d != math.Trunc(d) {
		panic("round: digits must be an integer-valued number")
	}
	if math.IsNaN(val) || math.IsInf(val, 0) {
		return val
	}
	m := math.Pow(10, d)
	scaled := val * m
	floor := math.Floor(scaled)
	diff := scaled - floor
	var rounded float64
	if diff < 0.5 {
		rounded = floor
	} else if diff > 0.5 {
		rounded = floor + 1
	} else {
		if math.Floor(floor/2)*2 == floor {
			rounded = floor
		} else {
			rounded = floor + 1
		}
	}
	return rounded / m
}

func steleCeil(a any) float64 {
	val := toFloat(a, "ceil")
	if math.IsNaN(val) {
		return math.NaN()
	}
	return math.Ceil(val)
}

func steleFloor(a any) float64 {
	val := toFloat(a, "floor")
	if math.IsNaN(val) {
		return math.NaN()
	}
	return math.Floor(val)
}

func toFloat(v any, op string) float64 {
	_, f, _, err := steleNumeric(v)
	if err != nil {
		f, ok := steleTryNumeric(v)
		if !ok {
			panic(fmt.Sprintf("%s: expected number, got %T", op, v))
		}
		return f
	}
	return f
}

