func steleSum(coll any, pathSegments ...string) float64 {
	items := asCollection(coll, "sum")
	projected := projectCollection(items, pathSegments)
	var total float64
	for i, v := range projected {
		total += toFloat(v, fmt.Sprintf("sum[%d]", i))
	}
	return total
}

func steleCount(coll any) int {
	items := asCollection(coll, "count")
	return len(items)
}

func steleAvg(coll any, pathSegments ...string) float64 {
	items := asCollection(coll, "avg")
	if len(items) == 0 {
		return 0
	}
	projected := projectCollection(items, pathSegments)
	var total float64
	for _, v := range projected {
		total += toFloat(v, "avg")
	}
	return total / float64(len(items))
}

func steleMin(coll any, pathSegments ...string) float64 {
	items := asCollection(coll, "min")
	if len(items) == 0 {
		panic("min: cannot compute min of an empty collection")
	}
	projected := projectCollection(items, pathSegments)
	result := toFloat(projected[0], "min")
	for i, v := range projected[1:] {
		val := toFloat(v, fmt.Sprintf("min[%d]", i+1))
		if val < result {
			result = val
		}
	}
	return result
}

func steleMax(coll any, pathSegments ...string) float64 {
	items := asCollection(coll, "max")
	if len(items) == 0 {
		panic("max: cannot compute max of an empty collection")
	}
	projected := projectCollection(items, pathSegments)
	result := toFloat(projected[0], "max")
	for i, v := range projected[1:] {
		val := toFloat(v, fmt.Sprintf("max[%d]", i+1))
		if val > result {
			result = val
		}
	}
	return result
}

func steleDistinct(coll any, pathSegments ...string) []any {
	items := asCollection(coll, "distinct")
	projected := projectCollection(items, pathSegments)
	seen := make(map[string]bool)
	result := []any{}
	for _, v := range projected {
		key := canonicalKey(v)
		if !seen[key] {
			seen[key] = true
			result = append(result, v)
		}
	}
	return result
}

func steleUnique(coll any, pathSegments ...string) bool {
	items := asCollection(coll, "unique")
	projected := projectCollection(items, pathSegments)
	seen := make(map[string]bool)
	for _, v := range projected {
		key := canonicalKey(v)
		if seen[key] {
			return false
		}
		seen[key] = true
	}
	return true
}

func steleHasLength(coll any, expected any) bool {
	exp, _, _, err := steleNumeric(expected)
	if err != nil {
		panic(fmt.Sprintf("has-length: expected length must be a number, got %T", expected))
	}
	return polymorphicLength(coll) == int(exp)
}

func steleIsEmpty(coll any) bool {
	return polymorphicLength(coll) == 0
}

func polymorphicLength(value any) int {
	switch v := value.(type) {
	case []any:
		return len(v)
	case string:
		return len(v)
	case map[string]any:
		return len(v)
	default:
		panic(fmt.Sprintf("cannot compute length of %T", value))
	}
}

func steleExistsIn(value any, container any) bool {
	switch c := container.(type) {
	case []any:
		for _, candidate := range c {
			if steleEq(candidate, value) {
				return true
			}
		}
		return false
	case string:
		v, ok := value.(string)
		if !ok {
			panic(fmt.Sprintf("exists-in: cannot test %T membership in a string container", value))
		}
		return strings.Contains(c, v)
	case map[string]any:
		v, ok := value.(string)
		if !ok {
			return false
		}
		_, ok = c[v]
		return ok
	default:
		panic(fmt.Sprintf("exists-in: container must be array, string, or object; got %T", container))
	}
}

