// steleJsonPath extracts a value from a JSON string using a simplified JSONPath expression.
func steleJsonPath(data any, pathExpr any) string {
	dataS, ok := data.(string)
	if !ok {
		panic(fmt.Sprintf("json-path: data must be a string, got %T", data))
	}
	pathS, ok := pathExpr.(string)
	if !ok {
		panic(fmt.Sprintf("json-path: path must be a string, got %T", pathExpr))
	}
	var root any
	if err := json.Unmarshal([]byte(dataS), &root); err != nil {
		panic(fmt.Sprintf("json-path: invalid JSON input: %v", err))
	}
	results := _steleEvalJsonPath(root, pathS)
	if len(results) == 1 {
		return fmt.Sprintf("%v", results[0])
	}
	b, _ := json.Marshal(results)
	return string(b)
}

func _steleEvalJsonPath(data any, path string) []any {
	if path == "" {
		return []any{data}
	}
	tokens := _steleTokenizePath(path)
	if len(tokens) == 0 {
		return []any{data}
	}
	kind, value := tokens[0]
	rest := _steleDetokenize(tokens[1:])
	switch kind {
	case "field":
		if m, ok := data.(map[string]any); ok {
			if v, exists := m[value.(string)]; exists {
				return _steleEvalJsonPath(v, rest)
			}
		}
		return nil
	case "index":
		if arr, ok := data.([]any); ok {
			idx := value.(int)
			if idx >= 0 && idx < len(arr) {
				return _steleEvalJsonPath(arr[idx], rest)
			}
		}
		return nil
	case "wildcard":
		if arr, ok := data.([]any); ok {
			var all []any
			for _, item := range arr {
				all = append(all, _steleEvalJsonPath(item, rest)...)
			}
			return all
		}
		return nil
	}
	return nil
}

type _JsonPathToken struct {
	kind  string
	value any
}

func _steleTokenizePath(path string) []_JsonPathToken {
	var tokens []_JsonPathToken
	i := 0
	for i < len(path) {
		if path[i] == '.' {
			i++
			continue
		}
		if path[i] == '[' {
			j := strings.Index(path[i:], "]")
			if j == -1 {
				panic("json-path: unclosed bracket in path")
			}
			j += i
			inner := path[i+1 : j]
			if inner == "*" {
				tokens = append(tokens, _JsonPathToken{kind: "wildcard"})
			} else {
				idx, err := strconv.Atoi(inner)
				if err != nil {
					panic(fmt.Sprintf("json-path: invalid array index: %q", inner))
				}
				tokens = append(tokens, _JsonPathToken{kind: "index", value: idx})
			}
			i = j + 1
			continue
		}
		start := i
		for i < len(path) && path[i] != '.' && path[i] != '[' {
			i++
		}
		name := path[start:i]
		if name != "" {
			tokens = append(tokens, _JsonPathToken{kind: "field", value: name})
		}
	}
	return tokens
}

func _steleDetokenize(tokens []_JsonPathToken) string {
	var sb strings.Builder
	for _, t := range tokens {
		switch t.kind {
		case "field":
			sb.WriteString(".")
			sb.WriteString(t.value.(string))
		case "index":
			sb.WriteString("[")
			sb.WriteString(strconv.Itoa(t.value.(int)))
			sb.WriteString("]")
		case "wildcard":
			sb.WriteString("[*]")
		}
	}
	return sb.String()
}

// steleDecimalEq compares two numbers with exact decimal precision.
func steleDecimalEq(left any, right any) bool {
	l, ok := left.(float64)
	if !ok {
		panic(fmt.Sprintf("decimal-eq: left must be a number, got %T", left))
	}
	r, ok := right.(float64)
	if !ok {
		panic(fmt.Sprintf("decimal-eq: right must be a number, got %T", right))
	}
	lStr := formatDecimal(l)
	rStr := formatDecimal(r)
	return lStr == rStr
}

func formatDecimal(v float64) string {
	if v == float64(int64(v)) {
		return strconv.FormatInt(int64(v), 10)
	}
	s := strconv.FormatFloat(v, 'f', 20, 64)
	// Trim trailing zeros after decimal point.
	if idx := strings.Index(s, "."); idx != -1 {
		s = strings.TrimRight(s, "0")
		s = strings.TrimRight(s, ".")
	}
	return s
}

// ---------------------------------------------------------------------------
// Collection operators
// ---------------------------------------------------------------------------

func steleLength(coll any) int {
	items := asCollection(coll, "length")
	return len(items)
}

func steleConcat(collections ...any) []any {
	if len(collections) < 1 {
		panic("concat: expected at least one collection")
	}
	out := []any{}
	for i, c := range collections {
		items := asCollection(c, fmt.Sprintf("concat[%d]", i))
		out = append(out, items...)
	}
	return out
}

// ---------------------------------------------------------------------------
// Data access
// ---------------------------------------------------------------------------

func steleTypeOf(value any) string {
	if value == nil {
		return "null"
	}
	switch value.(type) {
	case int, int8, int16, int32, int64, uint, uint8, uint16, uint32, uint64, float32, float64:
		return "number"
	case string:
		return "string"
	case bool:
		return "boolean"
	case []any:
		return "collection"
	default:
		return "object"
	}
}

// ---------------------------------------------------------------------------
// Control operators
// ---------------------------------------------------------------------------

func steleNotNull(value any) bool {
	return value != nil
}

func steleBetween(value, low, high any) bool {
	v := toFloat(value, "between")
	lo := toFloat(low, "between")
	hi := toFloat(high, "between")
	return lo <= v && v <= hi
}

func steleApproxEq(a, b, tolerance any) bool {
	left := toFloat(a, "approx-eq")
	right := toFloat(b, "approx-eq")
	tol := toFloat(tolerance, "approx-eq")
	return math.Abs(left-right) <= tol
}

// ---------------------------------------------------------------------------
// steleCompare helper (max-by / min-by)
// ---------------------------------------------------------------------------

// steleCompare returns -1, 0, or 1. Returns error for incomparable types.
func steleCompare(a, b any) (int, error) {
	ai, af, aF, aErr := steleNumeric(a)
	bi, bf, bF, bErr := steleNumeric(b)
	if aErr == nil && bErr == nil {
		if aF || bF {
			if math.Abs(af-bf) < 1e-9 {
				return 0, nil
			}
			if af < bf {
				return -1, nil
			}
			return 1, nil
		}
		if ai < bi {
			return -1, nil
		}
		if ai > bi {
			return 1, nil
		}
		return 0, nil
	}
	// string
	if as, ok := a.(string); ok {
		if bs, ok := b.(string); ok {
			return strings.Compare(as, bs), nil
		}
	}
	return 0, fmt.Errorf("cannot compare %T and %T", a, b)
}

// ---------------------------------------------------------------------------
// Collection transformations (sort-by, sort-by-desc, map, first, last)
// ---------------------------------------------------------------------------

func steleSortBy(coll []any, path []string) []any {
	result := make([]any, len(coll))
	copy(result, coll)
	sort.SliceStable(result, func(i, j int) bool {
		a, aErr := steleGetPath(result[i], path)
		b, bErr := steleGetPath(result[j], path)
		if aErr != nil || bErr != nil {
			return false
		}
		cmp, err := steleCompare(a, b)
		if err != nil {
			return false
		}
		return cmp < 0
	})
	return result
}

func steleSortByDesc(coll []any, path []string) []any {
	result := make([]any, len(coll))
	copy(result, coll)
	sort.SliceStable(result, func(i, j int) bool {
		a, aErr := steleGetPath(result[i], path)
		b, bErr := steleGetPath(result[j], path)
		if aErr != nil || bErr != nil {
			return false
		}
		cmp, err := steleCompare(a, b)
		if err != nil {
			return false
		}
		return cmp > 0
	})
	return result
}

func steleMap(coll []any, path []string) []any {
	result := make([]any, len(coll))
	for i, item := range coll {
		val, err := steleGetPath(item, path)
		if err != nil {
			panic(fmt.Sprintf("map: projection failed at index %d: %v", i, err))
		}
		result[i] = val
	}
	return result
}

func steleFirst(coll []any) any {
	if len(coll) == 0 {
		return nil
	}
	return coll[0]
}

func steleLast(coll []any) any {
	if len(coll) == 0 {
		return nil
	}
	return coll[len(coll)-1]
}

// ---------------------------------------------------------------------------
// Quantifiers (forall / exists / where / none)
// ---------------------------------------------------------------------------

func steleForall(t *testing.T, coll []any, pred func(any) bool, predSource string) error {
	for i, item := range coll {
		if !pred(item) {
			idx := i
			w := FailureWitness{
				Operator:        "forall",
				CollectionSize:  len(coll),
				FailedAtIndex:   &idx,
				FailedItem:      item,
				PredicateSource: predSource,
			}
			emitWitness(t, &w)
			return &SteleAssertionError{
				Message:  fmt.Sprintf("forall failed at index %d", i),
				Witness:  w,
				TestName: t.Name(),
			}
		}
	}
	return nil
}

func steleExists(t *testing.T, coll []any, pred func(any) bool, predSource string) error {
	for i, item := range coll {
		if pred(item) {
			return nil
		}
		_ = i
	}
	// No element satisfies.
	w := FailureWitness{
		Operator:        "exists",
		CollectionSize:  len(coll),
		PredicateSource: predSource,
	}
	if t != nil {
		emitWitness(t, &w)
	}
	return &SteleAssertionError{
		Message:  fmt.Sprintf("exists failed: no element in collection of size %d satisfies predicate", len(coll)),
		Witness:  w,
		TestName: t.Name(),
	}
}

func steleWhere(t *testing.T, coll []any, pred func(any) bool, predSource string) ([]any, error) {
	matched := []any{}
	for _, item := range coll {
		if pred(item) {
			matched = append(matched, item)
		}
	}
	return matched, nil
}

func steleNone(t *testing.T, coll []any, pred func(any) bool, predSource string) error {
	for i, item := range coll {
		if pred(item) {
			idx := i
			w := FailureWitness{
				Operator:        "none",
				CollectionSize:  len(coll),
				FailedAtIndex:   &idx,
				FailedItem:      item,
				PredicateSource: predSource,
			}
			emitWitness(t, &w)
			return &SteleAssertionError{
				Message:  fmt.Sprintf("none failed at index %d: predicate matched an element that should not match", i),
				Witness:  w,
				TestName: t.Name(),
			}
		}
	}
	return nil
}

// ---------------------------------------------------------------------------
// Temporal operators
// ---------------------------------------------------------------------------

func steleIsModified(ctx *SteleContext, segments []string) bool {
	before := ctx.Before
	after := ctx.After
	if before == nil || after == nil {
		panic("modified: state-before or state-after not set on context")
	}
	beforeVal := steleReadPath(before.Data, segments)
	afterVal := steleReadPath(after.Data, segments)
	if beforeVal == nil && afterVal == nil {
		return false
	}
	if beforeVal == nil || afterVal == nil {
		return true
	}
	return !steleEq(beforeVal, afterVal)
}

func steleStateBefore(ctx *SteleContext) *SteleContext {
	if ctx.Before == nil {
		panic("state-before: missing state-before on context")
	}
	return ctx.Before
}

func steleStateAfter(ctx *SteleContext) *SteleContext {
	if ctx.After == nil {
		panic("state-after: missing state-after on context")
	}
	return ctx.After
}

func steleWithin(eventSeconds, durationSeconds, now any) bool {
	event := toFloat(eventSeconds, "within")
	duration := toFloat(durationSeconds, "within")
	n := toFloat(now, "within")
	return event+duration > n
}

func steleBefore(left, right any) bool {
	return toFloat(left, "before") < toFloat(right, "before")
}

func steleAfter(left, right any) bool {
	return toFloat(left, "after") > toFloat(right, "after")
}

// ---------------------------------------------------------------------------
// Path access
// ---------------------------------------------------------------------------

// steleGetPath navigates a path through nested maps. Supports kebab -> snake
// fallback for idiomatic Go naming conventions.
func steleGetPath(obj any, segments []string) (any, error) {
	current := obj
	for _, seg := range segments {
		m, ok := current.(map[string]any)
		if !ok {
			return nil, fmt.Errorf("path navigation hit non-map at %q (got %T)", seg, current)
		}
		if v, hit := m[seg]; hit {
			current = v
			continue
		}
		// kebab -> snake fallback
		snake := strings.ReplaceAll(seg, "-", "_")
		if v, hit := m[snake]; hit {
			current = v
			continue
		}
		return nil, fmt.Errorf("path not found: %q on map keys %v", seg, mapKeys(m))
	}
	return current, nil
}

// steleGetPathVal is a wrapper that calls steleGetPath and panics on error.
// Used by generated test code where a single-return-value helper is needed.
func steleGetPathVal(obj any, segments []string) any {
	v, err := steleGetPath(obj, segments)
	if err != nil {
		panic(err)
	}
	return v
}

// steleReadPath is a variant of steleGetPath that returns nil instead of error
// for missing paths. Used by steleIsModified.
func steleReadPath(data map[string]any, segments []string) any {
	current := any(data)
	for _, seg := range segments {
		m, ok := current.(map[string]any)
		if !ok {
			return nil
		}
		if v, hit := m[seg]; hit {
			current = v
			continue
		}
		snake := strings.ReplaceAll(seg, "-", "_")
		if v, hit := m[snake]; hit {
			current = v
			continue
		}
		return nil
	}
	return current
}

// mapKeys returns all keys in a map, sorted for deterministic error output.
func mapKeys(m map[string]any) []string {
	keys := make([]string, 0, len(m))
	for k := range m {
		keys = append(keys, k)
	}
	sort.Strings(keys)
	return keys
}

// ---------------------------------------------------------------------------
// Checker invocation
// ---------------------------------------------------------------------------

func steleCallChecker(name string, args []any, ctx *SteleContext) (CheckerResult, error) {
	fn, ok := ctx.Checkers[name]
	if !ok {
		return CheckerResult{}, fmt.Errorf("checker %q not registered", name)
	}
	return fn(args, ctx), nil
}

// ---------------------------------------------------------------------------
// Scenario runtime
// ---------------------------------------------------------------------------

func steleRunScenario(steps []ScenarioStep, ctx *SteleContext) (*SteleContext, error) {
	current := new(SteleContext)
	current.Data = make(map[string]any)
	current.Checkers = make(map[string]CheckerFunc)
	// Copy from parent context.
	for k, v := range ctx.Data {
		current.Data[k] = v
	}
	for _, step := range steps {
		_ = step
		// Step execution would invoke the target function.
		// In the generated code, the user provides the execution logic.
	}
	return current, nil
}

// ---------------------------------------------------------------------------
// Context merging
// ---------------------------------------------------------------------------

func steleMergeContexts(contexts ...*SteleContext) *SteleContext {
	merged := NewContext()
	for _, ctx := range contexts {
		if ctx == nil {
			continue
		}
		for k, v := range ctx.Data {
			merged.Data[k] = v
		}
		for k, v := range ctx.Checkers {
			merged.Checkers[k] = v
		}
	}
	return merged
}

// ---------------------------------------------------------------------------
// steleToInterfaceSlice helper
// ---------------------------------------------------------------------------

// steleToInterfaceSlice converts any slice to []interface{}.
func steleToInterfaceSlice(v any) []any {
	val := reflect.ValueOf(v)
	if val.Kind() != reflect.Slice {
		return []any{v}
	}
	result := make([]any, val.Len())
	for i := 0; i < val.Len(); i++ {
		elem := val.Index(i)
		if !elem.CanInterface() {
			cpy := reflect.New(elem.Type()).Elem()
			cpy.Set(elem)
			result[i] = cpy.Interface()
		} else {
			result[i] = elem.Interface()
		}
	}
	return result
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

func asCollection(coll any, op string) []any {
	items, ok := coll.([]any)
	if !ok {
		panic(fmt.Sprintf("%s: expected []interface{}, got %T", op, coll))
	}
	return items
}

func projectCollection(items []any, segments []string) []any {
	if len(segments) == 0 {
		out := make([]any, len(items))
		copy(out, items)
		return out
	}
	result := make([]any, len(items))
	for i, item := range items {
		val, err := steleGetPath(item, segments)
		if err != nil {
			panic(fmt.Sprintf("projection failed at index %d: %v", i, err))
		}
		result[i] = val
	}
	return result
}

func canonicalKey(value any) string {
	if value == nil {
		return "n:null"
	}
	switch v := value.(type) {
	case string:
		return "s:" + v
	case int, int8, int16, int32, int64, uint, uint8, uint16, uint32, uint64, float32, float64:
		return "#:" + fmt.Sprint(v)
	case bool:
		return "b:" + fmt.Sprint(v)
	default:
		data, _ := json.Marshal(value)
		return "j:" + string(data)
	}
}

// steleAssertTrue asserts a condition is true, failing the test if not.
func steleAssertTrue(t *testing.T, cond bool, msg string) {
	t.Helper()
	if !cond {
		t.Errorf("%s", msg)
		t.FailNow()
	}
}

// ---------------------------------------------------------------------------
// Assert helper for generated tests (steleAssertTrue alias)
// ---------------------------------------------------------------------------

// _ is a sentinel to suppress "unused import" errors when helpers are not
// referenced by generated code in a given run.
var _ = steleAssertTrue

// ---------------------------------------------------------------------------
// Global context for generated test functions
// ---------------------------------------------------------------------------

// globalCtx is the default context used by generated invariant test functions.
// It is initialized in init() to a safe default. Override it in TestMain or
// setup_test.go with SetupSteleContext() to provide real data.
var globalCtx *SteleContext

func init() {
	if globalCtx == nil {
		globalCtx = NewContext()
	}
}
